from collections import defaultdict

class Solution(object):
    def longestEqualSubarray(self, nums, k):
        # For each value v, positions[v] = sorted list of indices where nums[i] == v
        positions = defaultdict(list)
        for i, v in enumerate(nums):
            positions[v].append(i)
        ans = 1
        for v, idxs in positions.items():
            # Sliding window on idxs: find max window [l..r] such that
            # (idxs[r] - idxs[l]) - (r - l) <= k  (number of deletions needed)
            l = 0
            for r in range(len(idxs)):
                # deletions = span - count = (idxs[r] - idxs[l]) - (r - l)
                while (idxs[r] - idxs[l]) - (r - l) > k:
                    l += 1
                ans = max(ans, r - l + 1)
        return ans
